/**
 * FinCEN CDD beneficial owner gate (Corporate Transparency Act;
 * 31 CFR §1010.380).
 *
 * Scenario #27 of guides/use-cases.md: a business AccountHolder with
 * kyc_status='approved' but ZERO disclosed beneficial owners may not
 * originate a payment. Individual / trust / nonprofit AHs are out of
 * scope of §1010.380 and pass through unchanged.
 *
 * Reads `debtor_payment_account.account_holder.account_holder_type`
 * and `.beneficial_owners[]` (preloaded by
 * `AccountHolderContext.@preloads` and serialized to the rule engine
 * via the standard public OpenAPI mapper — no payload-layer scaffolding).
 *
 * When the originating AH is `business` and `beneficial_owners` is
 * empty, emits a blocked Control per LedgerAccount on the debtor side.
 * cap=0 + is_blocked=true converts to status='rejected' with
 * rejected_rule='business_ah_zero_bos' at limits-at-entry time.
 */
export const handler = async (input) => {
  const debtor = input.debtor_payment_account;
  if (!debtor) return { ledger_accounts: {} };

  const ah = debtor.account_holder;
  if (!ah) return { ledger_accounts: {} };

  if (ah.account_holder_type !== 'business') {
    return { ledger_accounts: {} };
  }

  const bos = ah.beneficial_owners || [];
  if (bos.length > 0) return { ledger_accounts: {} };

  const las = debtor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'business_ah_zero_bos',
      block_reason: 'business_ah_zero_bos',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
